List<AdminModuleSpec> modulesForRole(AdminWebRole role) =>
    role == AdminWebRole.superAdmin ? superAdminModuleCatalog : adminModuleCatalog;

AdminModuleSpec moduleFor(String key, AdminWebRole role) {
  final modules = modulesForRole(role);
  return modules.firstWhere(
    (module) => module.key == key,
    orElse: () => modules.first,
  );
}
